import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";

function Result() {
  const navigate = useNavigate();
  const location = useLocation();
  const {
    gem_prediction,
    gem_confidence,
    shape_prediction,
    shape_confidence,
    image,
    show_shape,
  } = location.state || {};

  const gemConfidencePercent = (gem_confidence * 100).toFixed(1);
  const shapeConfidencePercent = show_shape ? (shape_confidence * 100).toFixed(1) : null;

  return (
    <>
      <Topnav />

      <main className="min-h-screen bg-gray-50 py-16 px-6">
        <div className="max-w-4xl mx-auto bg-white rounded-2xl shadow-lg p-8 md:p-12 text-center">
          <h1 className="text-3xl md:text-4xl font-bold text-gray-900 mb-8">
            Gem Analysis Result
          </h1>

          {image && (
            <div className="mb-10">
              <img
                src={URL.createObjectURL(image)}
                alt={gem_prediction || "Gem"}
                className="w-64 h-64 md:w-80 md:h-80 mx-auto rounded-full object-cover shadow-xl border-4 border-blue-100"
              />
            </div>
          )}

          <div className="space-y-8 text-lg">
            <div>
              <p className="text-gray-600">Gem</p>
              <p className="text-3xl font-bold text-blue-700">{gem_prediction || "Unknown"}</p>
              <p className="text-gray-600 mt-2">
                Confidence: <span className="font-semibold">{gemConfidencePercent}%</span>
              </p>
            </div>

            {show_shape && shape_prediction && (
              <div>
                <p className="text-gray-600">Shape / Cut</p>
                <p className="text-3xl font-bold text-blue-700 capitalize">{shape_prediction}</p>
                <p className="text-gray-600 mt-2">
                  Confidence: <span className="font-semibold">{shapeConfidencePercent}%</span>
                </p>
              </div>
            )}
          </div>

          <button
            onClick={() => navigate("/imageuploader")}
            className="mt-12 px-10 py-4 bg-blue-600 hover:bg-blue-700 text-white text-lg font-semibold rounded-full shadow-md hover:shadow-lg transition-all"
          >
            Re-Analyze Another Gem
          </button>
        </div>
      </main>
      <Footer />
    </>
  );
}

export default Result;
